292: func removeManagedFields(obj runtime.Object) error {
293: 	if obj == nil {
294: 		return nil
295: 	}
296: 	accessor, err := meta.Accessor(obj)
297: 	if err != nil {
298: 		return err
299: 	}
300: 	accessor.SetManagedFields(nil)
301: 	return nil
302: }
