18: 
19: import (
20: 	"fmt"
21: 	"io/ioutil"
22: 
23: 	"k8s.io/apimachinery/pkg/runtime"
24: 	"k8s.io/apimachinery/pkg/runtime/schema"
25: 	"k8s.io/apimachinery/pkg/runtime/serializer"
26: 	auditinternal "k8s.io/apiserver/pkg/apis/audit"
27: 	auditv1 "k8s.io/apiserver/pkg/apis/audit/v1"
28: 	"k8s.io/apiserver/pkg/apis/audit/validation"
29: 	"k8s.io/apiserver/pkg/audit"
30: 	"k8s.io/klog/v2"
31: )
32: 
33: var (
34: 	apiGroupVersions = []schema.GroupVersion{
35: 		auditv1.SchemeGroupVersion,
36: 	}
37: 	apiGroupVersionSet = map[schema.GroupVersion]bool{}
38: )
39: 
40: func init() {
41: 	for _, gv := range apiGroupVersions {
42: 		apiGroupVersionSet[gv] = true
43: 	}
44: }
